class Solution:
    def tallestBillboard(self, rods):
        n = len(rods)
        best = 0
        def rec(i, left, right):
            nonlocal best
            if i == n:
                if left == right:
                    best = max(best, left)
                return
            rec(i + 1, left + rods[i], right)
            rec(i + 1, left, right + rods[i])
            rec(i + 1, left, right)
        rec(0, 0, 0)
        return best

solutions.python:
class Solution:
    def tallestBillboard(self, rods):
        dp = {0: 0}
        for r in rods:
            cur = dict(dp)
            for diff, taller in dp.items():
                shorter = taller - diff
                d2 = diff + r
                cur[d2] = max(cur.get(d2, 0), taller + r)
                nd = abs(diff - r)
                cand = max(taller, shorter + r)
                cur[nd] = max(cur.get(nd, 0), cand)
            dp = cur
        return dp.get(0, 0)

