var tallestBillboard = function(rods) {
    let dp = new Map([[0, 0]]);
    for (const r of rods) {
        const cur = new Map(dp);
        for (const [diff, taller] of dp) {
            const shorter = taller - diff;
            const d2 = diff + r;
            cur.set(d2, Math.max(cur.get(d2) || 0, taller + r));
            const nd = Math.abs(diff - r);
            const cand = Math.max(taller, shorter + r);
            cur.set(nd, Math.max(cur.get(nd) || 0, cand));
        }
        dp = cur;
    }
    return dp.get(0) || 0;
};
